/* MedSys Logo - embedded as base64 */
const MEDSYS_LOGO = "data:image/jpeg;base64,";

// Inject logo everywhere once DOM is ready
(function injectLogos() {
  function setLogos() {
    const ids = ["login-logo","sidebar-logo","topbar-logo","about-logo","qr-label-logo"];
    ids.forEach(function(id){
      var el = document.getElementById(id);
      if(el) el.src = MEDSYS_LOGO;
    });
  }
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", setLogos);
  } else {
    setLogos();
  }
})();
